361→    private void buildAndVerifyTopology(final InternalTopologyBuilder builder) {
362→        builder.rewriteTopology(config);
363→        builder.buildTopology();
364→
365→        final Set<String> allInputTopicsCopy = new HashSet<>(allInputTopics);
366→
367→        // As we go, check each topology for overlap in the set of input topics/patterns
368→        final int numInputTopics = allInputTopicsCopy.size();
369→        final List<String> inputTopics = builder.fullSourceTopicNames();
370→        final Collection<String> inputPatterns = builder.allSourcePatternStrings();
371→
372→        final Set<String> newInputTopics = new HashSet<>(inputTopics);
373→        newInputTopics.addAll(inputPatterns);
374→
375→        final int numNewInputTopics = newInputTopics.size();
376→        allInputTopicsCopy.addAll(newInputTopics);
377→
378→        if (allInputTopicsCopy.size() != numInputTopics + numNewInputTopics) {
379→            inputTopics.retainAll(allInputTopicsCopy);
380→            inputPatterns.retainAll(allInputTopicsCopy);
381→            log.error("Tried to add the NamedTopology {} but it had overlap with other input topics {} or patterns {}",
382→                      builder.topologyName(), inputTopics, inputPatterns);
383→            throw new TopologyException("Named Topologies may not subscribe to the same input topics or patterns");
384→        }
385→
386→        final ProcessorTopology globalTopology = builder.buildGlobalStateTopology();
387→        if (globalTopology != null) {
388→            if (builder.topologyName() != null) {
389→                throw new IllegalStateException("Global state stores are not supported with Named Topologies");
390→            } else if (this.globalTopology != null) {
391→                throw new TopologyException("Topology builder had global state, but global topology has already been set");
392→            } else {
393→                this.globalTopology = globalTopology;
394→                globalStateStores.putAll(builder.globalStateStores());
395→            }
396→        }
397→        allInputTopics.addAll(newInputTopics);
398→    }
