 98→    @Override
 99→    public void init(final StateStoreContext stateStoreContext, final StateStore root) {
100→        internalContext = asInternalProcessorContext(stateStoreContext);
101→        cacheName = ThreadCache.nameSpaceFromTaskIdAndStore(internalContext.taskId().toString(), name());
102→        internalContext.registerCacheFlushListener(cacheName, entries -> {
103→            for (final ThreadCache.DirtyEntry entry : entries) {
104→                putAndMaybeForward(entry, internalContext);
105→            }
106→        });
107→        super.init(stateStoreContext, root);
108→        // save the stream thread as we only ever want to trigger a flush
109→        // when the stream thread is the current thread.
110→        streamThread = Thread.currentThread();
111→    }
