298→    @Override
299→    public byte[] putIfAbsent(final Bytes key,
300→                              final byte[] value) {
301→        Objects.requireNonNull(key, "key cannot be null");
302→        validateStoreOpen();
303→        lock.writeLock().lock();
304→        try {
305→            validateStoreOpen();
306→            final byte[] v = getInternal(key);
307→            if (v == null) {
308→                putInternal(key, value);
309→            }
310→            return v;
311→        } finally {
312→            lock.writeLock().unlock();
313→        }
314→    }
