 77→public class DefaultStateUpdater implements StateUpdater {
 78→
 79→    private static final String BUG_ERROR_MESSAGE = "This indicates a bug. " +
 80→        "Please report at https://issues.apache.org/jira/projects/KAFKA/issues or to the dev-mailing list (https://kafka.apache.org/contact).";
