 82→    private class StateUpdaterThread extends Thread {
 83→
 84→        private final ChangelogReader changelogReader;
 85→        private final StateUpdaterMetrics updaterMetrics;
 86→        private final AtomicBoolean isRunning = new AtomicBoolean(true);
 87→        private final AtomicBoolean isIdle = new AtomicBoolean(false);
 88→        private final Map<TaskId, Task> updatingTasks = new ConcurrentHashMap<>();
 89→        private final Map<TaskId, Task> pausedTasks = new ConcurrentHashMap<>();
 90→
 91→        private final WindowedSum idleTimeWindowedSum = new WindowedSum();
 92→        private final WindowedSum checkpointTimeWindowedSum = new WindowedSum();
 93→        private final WindowedSum activeRestoreTimeWindowedSum = new WindowedSum();
 94→        private final WindowedSum standbyRestoreTimeWindowedSum = new WindowedSum();
 95→        private final WindowedSum runOnceLatencyWindowedSum = new WindowedSum();
 96→        private final MetricConfig metricsConfig;
 97→
