 99→
100→        private long totalCheckpointLatency = 0L;
101→
102→        private volatile long fetchDeadlineClientInstanceId = -1L;
103→        private volatile KafkaFutureImpl<Uuid> clientInstanceIdFuture = new KafkaFutureImpl<>();
104→
105→        public StateUpdaterThread(final String name,
106→                                  final StreamsMetricsImpl metrics,
107→                                  final ChangelogReader changelogReader) {
108→            super(name);
109→            this.changelogReader = changelogReader;
110→            this.updaterMetrics = new StateUpdaterMetrics(metrics, name);
111→            this.metricsConfig = metrics.metricsRegistry().config();
