 56→/**
 57→ * This is the thread responsible for keeping all Global State Stores updated.
 58→ * It delegates most of the responsibility to the internal class StateConsumer
 59→ */
 60→public class GlobalStreamThread extends Thread {
 61→
 62→    private final Logger log;
 63→    private final LogContext logContext;
 64→    private final StreamsConfig config;
 65→    private final Consumer<byte[], byte[]> globalConsumer;
 66→    private final StateDirectory stateDirectory;
 67→    private final Time time;
 68→    private final ThreadCache cache;
 69→    private final StreamsMetricsImpl streamsMetrics;
 70→    private final ProcessorTopology topology;
 71→    private final AtomicLong cacheSize;
 72→    private volatile StreamsException startupException;
 73→    private java.util.function.Consumer<Throwable> streamsUncaughtExceptionHandler;
 74→    private volatile long fetchDeadlineClientInstanceId = -1;
 75→    private volatile KafkaFutureImpl<Uuid> clientInstanceIdFuture = new KafkaFutureImpl<>();
 76→    private final CountDownLatch initializationLatch = new CountDownLatch(1);
 77→
 78→    /**
 79→     * The states that the global stream thread can be in
 80→     *
 81→     * <pre>
 82→     *                +-------------+
 83→     *          +<--- | Created (0) |
 84→     *          |     +-----+-------+
 85→     *          |           |
 86→     *          |           v
 87→     *          |     +-----+-------+
 88→     *          +<--- | Running (1) |
 89→     *          |     +-----+-------+
 90→     *          |           |
 91→     *          |           v
 92→     *          |     +-----+-------+
 93→     *          +---> | Pending     |
 94→     *                | Shutdown (2)|
 95→     *                +-----+-------+
 96→     *                      |
 97→     *                      v
 98→     *                +-----+-------+
 99→     *                | Dead (3)    |
100→     *                +-------------+
101→     * </pre>
102→     *
103→     * Note the following:
104→     * <ul>
105→     *     <li>Any state can go to PENDING_SHUTDOWN. That is because streams can be closed at any time.</li>
106→     *     <li>State PENDING_SHUTDOWN may want to transit itself. In this case we will forbid the transition but will not treat as an error.</li>
107→     * </ul>
108→     */
109→    public enum State implements ThreadStateTransitionValidator {
110→        CREATED(1, 2), RUNNING(2), PENDING_SHUTDOWN(3), DEAD;
111→
112→        private final Set<Integer> validTransitions = new HashSet<>();
113→
114→        State(final Integer... validTransitions) {
115→            this.validTransitions.addAll(Arrays.asList(validTransitions));
116→        }
117→
118→        public boolean isRunning() {
119→            return equals(RUNNING);
120→        }
121→
122→        public boolean inErrorState() {
123→            return equals(DEAD) || equals(PENDING_SHUTDOWN);
124→        }
125→
126→        @Override
127→        public boolean isValidTransition(final ThreadStateTransitionValidator newState) {
128→            final State tmpState = (State) newState;
129→            return validTransitions.contains(tmpState.ordinal());
130→        }
131→    }
132→
133→    private volatile State state = State.CREATED;
134→    private final Object stateLock = new Object();
135→    private StreamThread.StateListener stateListener = null;
136→    private final String logPrefix;
137→    private final StateRestoreListener stateRestoreListener;
138→
139→    /**
140→     * Set the {@link StreamThread.StateListener} to be notified when state changes. Note this API is internal to
141→     * Kafka Streams and is not intended to be used by an external application.
142→     */
143→    public void setStateListener(final StreamThread.StateListener listener) {
144→        stateListener = listener;
145→    }
146→
147→    /**
148→     * @return The state this instance is in
149→     */
150→    public State state() {
151→        // we do not need to use the stat lock since the variable is volatile
152→        return state;
153→    }
154→
155→    /**
156→     * Sets the state
157→     *
158→     * @param newState New state
159→     */
160→    private void setState(final State newState) {
161→        final State oldState = state;
162→
163→        synchronized (stateLock) {
164→            if (state == State.PENDING_SHUTDOWN && newState == State.PENDING_SHUTDOWN) {
165→                // when the state is already in PENDING_SHUTDOWN, its transition to itself
166→                // will be refused but we do not throw exception here
167→                return;
168→            } else if (state == State.DEAD) {
169→                // when the state is already in NOT_RUNNING, all its transitions
170→                // will be refused but we do not throw exception here
171→                return;
172→            } else if (!state.isValidTransition(newState)) {
173→                log.error("Unexpected state transition from {} to {}", oldState, newState);
174→                throw new StreamsException(logPrefix + "Unexpected state transition from " + oldState + " to " + newState);
175→            } else {
176→                log.info("State transition from {} to {}", oldState, newState);
177→            }
178→
179→            state = newState;
180→        }
181→
182→        if (stateListener != null) {
183→            stateListener.onChange(this, state, oldState);
184→        }
185→    }
186→
187→    public boolean stillRunning() {
188→        synchronized (stateLock) {
189→            return state.isRunning();
190→        }
191→    }
192→
193→    public boolean inErrorState() {
194→        synchronized (stateLock) {
195→            return state.inErrorState();
196→        }
197→    }
