221→        this.streamsUncaughtExceptionHandler = streamsUncaughtExceptionHandler;
222→        this.cacheSize = new AtomicLong(-1L);
223→    }
224→
225→    static class StateConsumer {
226→        private final Consumer<byte[], byte[]> globalConsumer;
227→        private final GlobalStateMaintainer stateMaintainer;
228→        private final Duration pollTime;
229→        private final Logger log;
230→
231→        StateConsumer(final LogContext logContext,
232→                      final Consumer<byte[], byte[]> globalConsumer,
233→                      final GlobalStateMaintainer stateMaintainer,
234→                      final Duration pollTime) {
235→            this.log = logContext.logger(getClass());
236→            this.globalConsumer = globalConsumer;
237→            this.stateMaintainer = stateMaintainer;
238→            this.pollTime = pollTime;
239→        }
240→
241→        /**
242→         * @throws IllegalStateException If a store gets registered after initialized is already finished
243→         * @throws StreamsException      if the store's change log does not contain the partition
244→         */
245→        void initialize() {
246→            final Map<TopicPartition, Long> partitionOffsets = stateMaintainer.initialize();
247→            globalConsumer.assign(partitionOffsets.keySet());
248→            for (final Map.Entry<TopicPartition, Long> entry : partitionOffsets.entrySet()) {
249→                globalConsumer.seek(entry.getKey(), entry.getValue());
250→            }
251→        }
252→
253→        void pollAndUpdate() {
254→            final ConsumerRecords<byte[], byte[]> received = globalConsumer.poll(pollTime);
255→            for (final ConsumerRecord<byte[], byte[]> record : received) {
256→                stateMaintainer.update(record);
257→            }
258→            stateMaintainer.maybeCheckpoint();
259→        }
260→
261→        public void close(final boolean wipeStateStore) throws IOException {
262→            try {
263→                globalConsumer.close();
264→            } catch (final RuntimeException e) {
265→                // just log an error if the consumer throws an exception during close
266→                // so we can always attempt to close the state stores.
267→                log.error("Failed to close global consumer due to the following error:", e);
268→            }
269→
270→            stateMaintainer.close(wipeStateStore);
271→        }
272→    }
273→
274→    @Override
275→    public void run() {
276→        final StateConsumer stateConsumer = initialize();
277→
278→        if (stateConsumer == null) {
279→            // during initialization, the caller thread would wait for the state consumer
280→            // to restore the global state store before transiting to RUNNING state and return;
281→            // if an error happens during the restoration process, the stateConsumer will be null
282→            // and in this case we will transit the state to PENDING_SHUTDOWN and DEAD immediately.
283→            // the exception will be thrown in the caller thread during start() function.
284→            setState(State.PENDING_SHUTDOWN);
285→            setState(State.DEAD);
286→
287→            log.error("Error happened during initialization of the global state store; this thread has shutdown.");
288→            streamsMetrics.removeAllThreadLevelSensors(getName());
289→            streamsMetrics.removeAllThreadLevelMetrics(getName());
290→
291→            return;
292→        }
293→
294→        boolean wipeStateStore = false;
295→        try {
296→            while (stillRunning()) {
297→                final long size = cacheSize.getAndSet(-1L);
298→                if (size != -1L) {
299→                    cache.resize(size);
300→                }
301→                stateConsumer.pollAndUpdate();
302→
303→                if (fetchDeadlineClientInstanceId != -1) {
304→                    if (fetchDeadlineClientInstanceId >= time.milliseconds()) {
305→                        try {
306→                            // we pass in a timeout of zero, to just trigger the "get instance id" background RPC,
307→                            // we don't want to block the global thread that can do useful work in the meantime
308→                            clientInstanceIdFuture.complete(globalConsumer.clientInstanceId(Duration.ZERO));
309→                            fetchDeadlineClientInstanceId = -1;
310→                        } catch (final IllegalStateException disabledError) {
311→                            // if telemetry is disabled on a client, we swallow the error,
312→                            // to allow returning a partial result for all other clients
313→                            clientInstanceIdFuture.complete(null);
314→                            fetchDeadlineClientInstanceId = -1;
315→                        } catch (final TimeoutException swallow) {
316→                            // swallow
317→                        } catch (final Exception error) {
318→                            clientInstanceIdFuture.completeExceptionally(error);
319→                            fetchDeadlineClientInstanceId = -1;
320→                        }
321→                    } else {
322→                        clientInstanceIdFuture.completeExceptionally(
323→                            new TimeoutException("Could not retrieve global consumer client instance id.")
324→                        );
325→                        fetchDeadlineClientInstanceId = -1;
326→                    }
327→                }
328→            }
329→        } catch (final InvalidOffsetException recoverableException) {
330→            wipeStateStore = true;
331→            log.error(
332→                "Updating global state failed due to inconsistent local state. Will attempt to clean up the local state. You can restart KafkaStreams to recover from this error.",
333→                recoverableException
334→            );
335→            final StreamsException e = new StreamsException(
336→                "Updating global state failed. You can restart KafkaStreams to launch a new GlobalStreamThread to recover from this error.",
337→                recoverableException
338→            );
339→            this.streamsUncaughtExceptionHandler.accept(e);
340→        } catch (final Exception e) {
341→            log.error("Error happened while maintaining global state store. The streams application or client will now close to ERROR.", e);
342→            this.streamsUncaughtExceptionHandler.accept(e);
343→        } finally {
344→            // set the state to pending shutdown first as it may be called due to error;
345→            // its state may already be PENDING_SHUTDOWN so it will return false but we
346→            // intentionally do not check the returned flag
347→            setState(State.PENDING_SHUTDOWN);
348→
349→            log.info("Shutting down");
